const KIND_TO_ICON: Record<FileIconKind, string> = {
  json: "file-type-json",
  jsonc: "file-type-json",
  csharp: "file-type-csharp",
  javascript: "file-type-js",
  typescript: "file-type-typescript",
  tsx: "file-type-reactts",
  jsx: "file-type-reactjs",
  python: "file-type-python",
  markdown: "file-type-markdown",
  html: "file-type-html",
  css: "file-type-css",
  scss: "file-type-scss",
  less: "file-type-less",
  xml: "file-type-xml",
  svg: "file-type-svg",
  yaml: "file-type-yaml",
  shell: "file-type-shell",
  powershell: "file-type-powershell",
  rust: "file-type-rust",
  go: "file-type-go",
  java: "file-type-java",
  kotlin: "file-type-kotlin",
  ruby: "file-type-ruby",
  php: "file-type-php",
  sql: "file-type-sql",
  docker: "file-type-docker",
  toml: "file-type-toml",
  ini: "file-type-ini",
  env: "file-type-dotenv",
  config: "file-type-config",
  git: "file-type-git",
  proto: "file-type-protobuf",
  text: "file-type-text",
  generic: "file-type-text",
};

export function getFileTypeIconSvg(kind: FileIconKind): string {
  const key = KIND_TO_ICON[kind] ?? KIND_TO_ICON.generic;
  return ICON_SVG[key] ?? ICON_SVG[KIND_TO_ICON.generic];
}